CustomField.formula:
/* Count number of days between End Date & January 1 1900 AD */
(
    (
        End_Date__c
        + 1
    )
    - (
        DATE(
            1900,
            1,
            1
        )
        - 1
    )
)
/* Add number of days between noon January 1 4713 BC & January 1 1900 AD. This results in a Julian End Date */
+ 2415018.5
